import time
import psutil
import os
from contextlib import contextmanager
from metrics import (
    records_read, records_written, records_failed,
    pipeline_duration, stage_duration,
    validation_failures, pipeline_last_success_timestamp,
    memory_rss
)

PIPELINE_NAME = "user_events"

@contextmanager
def measure_stage(name: str):
    """Context manager that measures wall-clock duration of a stage."""
    start = time.monotonic()
    try:
        yield
    finally:
        elapsed = time.monotonic() - start
        stage_duration.labels(
            pipeline_name=PIPELINE_NAME, stage=name
        ).observe(elapsed)

def emit_resource_metrics():
    proc = psutil.Process(os.getpid())
    memory_rss.labels(pipeline_name=PIPELINE_NAME).set(
        proc.memory_info().rss
    )

def extract(source_path: str) -> list[dict]:
    with measure_stage("extract"):
        rows = []
        with open(source_path) as f:
            for line in f:
                row = parse_line(line)  # your parsing logic
                rows.append(row)
                records_read.labels(
                    pipeline_name=PIPELINE_NAME, source=source_path
                ).inc()
        return rows

def validate(rows: list[dict]) -> tuple[list[dict], list[dict]]:
    with measure_stage("validate"):
        good, bad = [], []
        for row in rows:
            if row.get("user_id") is None:
                validation_failures.labels(
                    pipeline_name=PIPELINE_NAME, check_name="null_user_id"
                ).inc()
                records_failed.labels(
                    pipeline_name=PIPELINE_NAME, reason="null_user_id"
                ).inc()
                bad.append(row)
            elif not isinstance(row.get("event_ts"), (int, float)):
                validation_failures.labels(
                    pipeline_name=PIPELINE_NAME, check_name="invalid_timestamp"
                ).inc()
                records_failed.labels(
                    pipeline_name=PIPELINE_NAME, reason="invalid_timestamp"
                ).inc()
                bad.append(row)
            else:
                good.append(row)
        return good, bad

def load(rows: list[dict], destination: str):
    with measure_stage("load"):
        write_to_db(rows, destination)  # your write logic
        records_written.labels(
            pipeline_name=PIPELINE_NAME, destination=destination
        ).inc(len(rows))

def run_pipeline(source_path: str, destination: str):
    start = time.monotonic()
    try:
        emit_resource_metrics()
        raw_rows = extract(source_path)
        good_rows, bad_rows = validate(raw_rows)
        load(good_rows, destination)
        handle_dead_letters(bad_rows)  # write to DLQ or log

        # Record overall duration and success timestamp
        elapsed = time.monotonic() - start
        pipeline_duration.labels(pipeline_name=PIPELINE_NAME).observe(elapsed)
        pipeline_last_success_timestamp.labels(
            pipeline_name=PIPELINE_NAME
        ).set(time.time())

    except Exception as e:
        records_failed.labels(
            pipeline_name=PIPELINE_NAME, reason="pipeline_exception"
        ).inc()
        raise

import logging
import json

class JSONFormatter(logging.Formatter):
    def format(self, record: logging.LogRecord) -> str:
        payload = {
            "ts": self.formatTime(record),
            "level": record.levelname,
            "msg": record.getMessage(),
            "pipeline": "user_events",
            "module": record.module,
        }
        if record.exc_info:
            payload["exception"] = self.formatException(record.exc_info)
        # Attach any extra fields
        for key, val in record.__dict__.items():
            if key not in logging.LogRecord.__dict__ and not key.startswith("_"):
                payload[key] = val
        return json.dumps(payload)

def get_logger(name: str) -> logging.Logger:
    logger = logging.getLogger(name)
    handler = logging.StreamHandler()
    handler.setFormatter(JSONFormatter())
    logger.addHandler(handler)
    logger.setLevel(logging.INFO)
    return logger

logger = get_logger("pipeline.user_events")

# Usage with structured extra fields:
logger.info(
