)

from dataclasses import dataclass, field
from typing import Any
import statistics

@dataclass
class QualityReport:
    pipeline: str
    total_records: int = 0
    null_counts: dict[str, int] = field(default_factory=dict)
    type_errors: dict[str, int] = field(default_factory=dict)
    range_violations: dict[str, int] = field(default_factory=dict)
    duplicates: int = 0
    field_stats: dict[str, list] = field(default_factory=dict)

    def check(self, row: dict[str, Any], required_fields: list[str],
               numeric_ranges: dict[str, tuple]) -> bool:
        self.total_records += 1
        valid = True

        for field_name in required_fields:
            if row.get(field_name) is None:
                self.null_counts[field_name] = self.null_counts.get(field_name, 0) + 1
                valid = False

        for field_name, (min_val, max_val) in numeric_ranges.items():
            val = row.get(field_name)
            if val is not None:
                if not isinstance(val, (int, float)):
                    self.type_errors[field_name] = self.type_errors.get(field_name, 0) + 1
                    valid = False
                elif not (min_val <= val <= max_val):
                    self.range_violations[field_name] = (
                        self.range_violations.get(field_name, 0) + 1
                    )
                    valid = False

                # Collect for distribution stats
                if field_name not in self.field_stats:
                    self.field_stats[field_name] = []
                self.field_stats[field_name].append(val)

        return valid

    def emit_to_prometheus(self, validation_failures_counter, pipeline_name: str):
        for field_name, count in self.null_counts.items():
            validation_failures_counter.labels(
                pipeline_name=pipeline_name,
                check_name=f"null_{field_name}"
            ).inc(count)

        for field_name, count in self.range_violations.items():
            validation_failures_counter.labels(
                pipeline_name=pipeline_name,
                check_name=f"range_violation_{field_name}"
            ).inc(count)

    def summary(self) -> dict:
        result = {
            "total": self.total_records,
            "null_counts": self.null_counts,
            "type_errors": self.type_errors,
            "range_violations": self.range_violations,
            "duplicates": self.duplicates,
        }
        for field_name, values in self.field_stats.items():
            if values:
                result[f"{field_name}_mean"] = statistics.mean(values)
                result[f"{field_name}_stdev"] = (
                    statistics.stdev(values) if len(values) > 1 else 0.0
                )
        return result

report = QualityReport(pipeline="user_events")

for row in raw_rows:
    is_valid = report.check(
        row,
        required_fields=["user_id", "event_ts", "event_type"],
        numeric_ranges={"amount_usd": (0.0, 100_000.0), "quantity": (1, 10_000)}
    )
    if is_valid:
        good_rows.append(row)
    else:
        bad_rows.append(row)

report.emit_to_prometheus(validation_failures, PIPELINE_NAME)
logger.info("Quality report", extra=report.summary())

import json
import time
from pathlib import Path

class DeadLetterWriter:
    """Writes failed records to a JSON Lines file with failure context."""

    def __init__(self, pipeline_name: str, base_path: str = "/tmp/dlq"):
        self.pipeline_name = pipeline_name
        self.path = Path(base_path) / f"{pipeline_name}_{int(time.time())}.jsonl"
        self.path.parent.mkdir(parents=True, exist_ok=True)
        self._file = self.path.open("w")
        self.count = 0

    def write(self, record: dict, reason: str, exception: Exception | None = None):
        entry = {
            "ts": time.time(),
            "pipeline": self.pipeline_name,
            "reason": reason,
            "record": record,
            "exception": str(exception) if exception else None,
        }
        self._file.write(json.dumps(entry) + "\n")
        self.count += 1

    def close(self):
        self._file.close()

    def __enter__(self):
        return self

    def __exit__(self, *args):
        self.close()
with DeadLetterWriter("user_events") as dlq:
